class Solution:
    def decompressRLElist(self, nums):
        out = []
        for i in range(0, len(nums), 2):
            freq, val = nums[i], nums[i + 1]
            for _ in range(freq):
                out.append(val)
        return out

solutions.python:
class Solution:
    def decompressRLElist(self, nums):
        res = []
        for i in range(0, len(nums), 2):
            res.extend([nums[i + 1]] * nums[i])
        return res

